/** Resolve icon name string to component */
export function resolveIcon(iconName: string, size = 14): React.ReactNode {
  const iconMap: Record<string, React.ComponentType<IconProps>> = {
    chefHat: IconChefHat,
    fire: IconFire,
    flash: IconFlash,
    clipboard: IconClipboard,
    check: IconCheck,
    minusSquare: IconMinusSquare,
    forkKnife: IconForkKnife,
    edit: IconEdit,
    x: IconX,
    search: IconSearch,
    chart: IconChart,
    stopwatch: IconStopwatch,
    volume: IconVolume,
    volumeMute: IconVolumeMute,
    settings: IconSettings,
  };
  const Component = iconMap[iconName];
  if (!Component) return null;
  return <Component size={size} />;
}
